[CmdletBinding()]param([string]$DatabaseUrl=$env:DATABASE_URL,[string]$OutputDirectory=".\backups")
$ErrorActionPreference='Stop';if([string]::IsNullOrWhiteSpace($DatabaseUrl)){throw 'DATABASE_URL is required.'};New-Item -ItemType Directory -Force -Path $OutputDirectory|Out-Null;$stamp=Get-Date -Format 'yyyyMMdd-HHmmss';$file=Join-Path $OutputDirectory "matrix-$stamp.dump";& pg_dump --format=custom --no-owner --no-acl --dbname=$DatabaseUrl --file=$file;if($LASTEXITCODE-ne 0){throw 'pg_dump failed.'};Get-FileHash $file -Algorithm SHA256|Format-List;Write-Host "Backup created: $file" -ForegroundColor Green
